mapper.select:
SELECT TO_CHAR(TO_DATE(EC.AR_DATE_STR,'YYYY/MM/DD'),'DD/MM/YYYY') AS AR_DATE_STR, TO_CHAR(TO_DATE(REPLACE(EC.AR_DATE_STR,'/','.'),'YYYY.MM.DD'),'DD.MM.YYYY') AS DATE_STR, EC.PK_NO AS APPLY_NO, EC.PERSON_ID, TO_CHAR(EC.FROM_TIME,'DD-MM-YYYY HH24:MI') AS FROM_DATE, TO_CHAR(EC.TO_TIME,'DD-MM-YYYY HH24:MI') AS TO_DATE, TO_CHAR(EC.QUANTITY) AS WORK_HOUR, EC.ITEM_NO, GET_GLOBAL_NAME(EC.ITEM_NO,#{lang, jdbcType=VARCHAR}) AS ITEM_NO_NAME, TO_CHAR(EC.CREATE_DATE,'DD-MM-YYYY') AS CREATE_DATE, GET_LOCAL_NAME_BY_PERSONID(EC.CREATED_BY,#{cpnyId, jdbcType=VARCHAR}) AS CREATED_NAME, TO_CHAR(EC.UPDATE_DATE,'DD-MM-YYYY') AS UPDATE_DATE, GET_LOCAL_NAME_BY_PERSONID(EC.UPDATED_BY,#{cpnyId, jdbcType=VARCHAR}) AS UPDATED_NAME, GET_AR_MAC_TIME(EC.PERSON_ID,EC.AR_DATE_STR,'IN') AS INDOOR_TIME, GET_AR_MAC_TIME(EC.PERSON_ID,EC.AR_DATE_STR,'OUT') AS OUTDOOR_TIME, TO_CHAR(TO_DATE(GET_AR_SHIFT_START_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'DD/MM/YYYY') AS SHIFT_START_YEAR, TO_CHAR(TO_DATE(GET_AR_SHIFT_START_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'HH24') AS SHIFT_START_HH, TO_CHAR(TO_DATE(GET_AR_SHIFT_START_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'MI') AS SHIFT_START_MI, TO_CHAR(TO_DATE(GET_AR_SHIFT_END_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'DD/MM/YYYY') AS SHIFT_END_YEAR, TO_CHAR(TO_DATE(GET_AR_SHIFT_END_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'HH24') AS SHIFT_END_HH, TO_CHAR(TO_DATE(GET_AR_SHIFT_END_TIME(EC.PERSON_ID,EC.AR_DATE_STR,#{cpnyId, jdbcType=VARCHAR}),'YYYY/MM/DD HH24:MI'),'MI') AS SHIFT_END_MI, HR.EMPID, HR.LOCAL_NAME, HR.DEPTNO, GET_DEPT_NAME(HR.DEPTNO,#{lang, jdbcType=VARCHAR}) AS DEPT_NAME, GET_GLOBAL_NAME(HR.POST_GRADE_NO,#{lang, jdbcType=VARCHAR}) AS POST_GRADE_NAME, HR.POST_FAMILY, GET_GLOBAL_NAME(HR.POST_FAMILY,#{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, EC.SHIFT_NO, GET_GLOBAL_NAME(EC.SHIFT_NO,#{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, EC.REMARK, GET_UPDATED_INFO(EC.CREATED_BY) AS CREATED_BY, GET_UPDATED_INFO(EC.UPDATED_BY) AS UPDATED_BY, EC.LOCK_YN FROM AR_DETAIL_HTSV EC, HR_EMPLOYEE HR WHERE EC.PERSON_ID = HR.PERSON_ID AND HR.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND HR.PERSON_ID NOT LIKE '111111%' AND EC.AR_DATE_STR NOT IN ( SELECT AR_DATE_STR FROM ESS_CARD_APPLY_TB CARD WHERE AFFIRM_FLAG IN ('14014306','14014307','14014308') AND CARD.CONFIRM_FLAG <> '2' AND PERSON_ID = EC.PERSON_ID ) AND EC.ITEM_NO IN ('141443','141441','141442','14015448') AND EC.AR_DATE_STR < TO_CHAR(SYSDATE,'YYYY/MM/DD') AND ( EXISTS ( SELECT B1.DEPTID FROM HR_DEPARTMENT B1 WHERE B1.DEPTNO = HR.DEPTNO START WITH B1.DEPTNO IN ( SELECT HRD.DEPTID FROM HR_DEPARTMENT HRD WHERE HRD.MANAGER_EMP_ID = #{adminID, jdbcType=VARCHAR} ) CONNECT BY PRIOR B1.DEPTNO = B1.PARENT_DEPT_NO UNION SELECT AR_SUPERVISOR_INFO.DEPTNO FROM AR_SUPERVISOR_INFO WHERE AR_SUPERVISOR_INFO.DEPTNO = HR.DEPTNO AND AR_SUPERVISOR_INFO.PERSON_ID = #{adminID, jdbcType=VARCHAR} ) )
AND ( UPPER(HR.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(HR.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HR.DEPTNO || ',') > 0
AND EC.AR_DATE_STR >= TO_CHAR(TO_DATE(#{fromDate, jdbcType=VARCHAR},'DD/MM/YYYY'),'YYYY/MM/DD')
AND EC.AR_DATE_STR <= TO_CHAR(TO_DATE(#{toDate, jdbcType=VARCHAR},'DD/MM/YYYY'),'YYYY/MM/DD')
AND HR.POST_FAMILY = #{postFamily, jdbcType=VARCHAR}
AND EC.SHIFT_NO = #{shiftNo, jdbcType=VARCHAR}
AND EC.ITEM_NO = #{itemNo, jdbcType=VARCHAR}
ORDER BY EC.AR_DATE_STR DESC

SELECT EC.APPLY_NO, TO_CHAR(TO_DATE(EC.AR_DATE_STR, 'YYYY/MM/DD'), 'DD/MM/YYYY') AS AR_DATE_STR, TO_CHAR(TO_DATE(REPLACE(EC.AR_DATE_STR, '/', '.'), 'YYYY.MM.DD'), 'DD.MM.YYYY') AS DATE_STR, EC.PERSON_ID, TO_CHAR(EC.FROM_TIME, 'DD/MM/YYYY HH24:MI') AS FROM_DATE, TO_CHAR(EC.TO_TIME, 'DD/MM/YYYY HH24:MI') AS TO_DATE, TO_CHAR(EC.WORK_HOUR) AS WORK_HOUR, EC.ITEM_NO, GET_GLOBAL_NAME(EC.ITEM_NO, #{lang, jdbcType=VARCHAR}) AS ITEM_NO_NAME, TO_CHAR(EC.CREATE_DATE, 'DD/MM/YYYY') AS CREATE_DATE, GET_LOCAL_NAME_BY_PERSONID(EC.CREATED_BY, #{cpnyId, jdbcType=VARCHAR}) AS CREATED_NAME, TO_CHAR(EC.UPDATE_DATE, 'DD/MM/YYYY') AS UPDATE_DATE, GET_LOCAL_NAME_BY_PERSONID(EC.UPDATED_BY, #{cpnyId, jdbcType=VARCHAR}) AS UPDATED_NAME, HR.EMPID, HR.LOCAL_NAME, HR.DEPTNO, GET_DEPT_NAME(HR.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, GET_GLOBAL_NAME(HR.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS POST_GRADE_NAME, HR.POST_FAMILY, GET_GLOBAL_NAME(HR.POST_FAMILY, #{lang, jdbcType=VARCHAR}) AS POST_FAMILY_NAME, GET_AR_SHIFTNO(EC.PERSON_ID, EC.AR_DATE_STR, #{cpnyId, jdbcType=VARCHAR}) AS SHIFT_NO, GET_GLOBAL_NAME(GET_AR_SHIFTNO(EC.PERSON_ID, EC.AR_DATE_STR, #{cpnyId, jdbcType=VARCHAR}), #{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, EC.APPLY_REASON AS REMARK, GET_UPDATED_INFO(EC.CREATED_BY) AS CREATED_BY, GET_UPDATED_INFO(EC.UPDATED_BY) AS UPDATED_BY, EC.CONFIRM_FLAG AS LOCK_YN FROM ESS_CARD_APPLY_TB EC INNER JOIN HR_EMPLOYEE HR ON EC.PERSON_ID = HR.PERSON_ID WHERE HR.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND HR.PERSON_ID NOT LIKE '111111%' AND EC.ITEM_NO IN ('141443', '141442', '141441', '14015448') AND EXISTS ( SELECT B1.DEPTID FROM HR_DEPARTMENT B1 WHERE B1.DEPTNO = HR.DEPTNO START WITH B1.DEPTNO IN ( SELECT HRD.DEPTID FROM HR_DEPARTMENT HRD WHERE HRD.MANAGER_EMP_ID = #{adminID, jdbcType=VARCHAR} ) CONNECT BY PRIOR B1.DEPTNO = B1.PARENT_DEPT_NO UNION SELECT AR_SUPERVISOR_INFO.DEPTNO FROM AR_SUPERVISOR_INFO WHERE AR_SUPERVISOR_INFO.DEPTNO = HR.DEPTNO AND AR_SUPERVISOR_INFO.PERSON_ID = #{adminID, jdbcType=VARCHAR} )
AND ( UPPER(HR.EMPID) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' OR UPPER(HR.LOCAL_NAME) LIKE '%' || UPPER(#{keyword, jdbcType=VARCHAR}) || '%' )
AND INSTR(',' || #{deptNos, jdbcType=VARCHAR} || ',', ',' || HR.DEPTNO || ',') > 0
AND EC.AR_DATE_STR >= TO_CHAR(TO_DATE(#{fromDate, jdbcType=VARCHAR}, 'DD/MM/YYYY'), 'YYYY/MM/DD')
AND EC.AR_DATE_STR <= TO_CHAR(TO_DATE(#{toDate, jdbcType=VARCHAR}, 'DD/MM/YYYY'), 'YYYY/MM/DD')
AND HR.POST_FAMILY = #{postFamily, jdbcType=VARCHAR}
AND GET_AR_SHIFTNO(EC.PERSON_ID, EC.AR_DATE_STR, #{cpnyId, jdbcType=VARCHAR}) = #{shiftNo, jdbcType=VARCHAR}
AND EC.ITEM_NO = #{itemNo, jdbcType=VARCHAR}
ORDER BY EC.AR_DATE_STR DESC, EC.CREATE_DATE DESC, EC.APPLY_NO DESC

SELECT T.SEQ, T.AFFIRM_TYPE, T.AFFIRM_TYPE_NAME, T.APPLY_NO, T.APPLY_TYPE, T.APPLY_FLAG, T.APPLY_PERSON_ID, T.AFFIRM_PERSON_ID, T.TITLE, T.AFFIRM_LEVEL, T.AFFIRM_FLAG, T.AFFIRM_URL, T.APPLY_TYPE_CODE, T.APPLY_PERSON_INFO, T.ACTIVITY, T.AFFIRM_FLAG_NAME, T.AFFIRM_NAME, T.DEPTNAME, T.APPLY_AFFIRM_FLAG_NO, T.APPLY_AFFIRM_FLAG, T.UPDATE_DATE, T.AFFIRM_CONTENT FROM ( SELECT A.SEQ, A.AFFIRM_TYPE, DECODE(A.AFFIRM_TYPE, '1', 'Approval', '2', 'Agreement', '3', 'Announcement', '4', 'Proposal', 'Approval') AS AFFIRM_TYPE_NAME, A.APPLY_NO, A.APPLY_TYPE, A.APPLY_FLAG, A.APPLY_PERSON_ID, A.AFFIRM_PERSON_ID, A.TITLE, TO_CHAR(A.AFFIRM_LEVEL) AS AFFIRM_LEVEL, A.AFFIRM_FLAG, A.AFFIRM_URL, A.APPLY_TYPE_CODE, A.APPLY_PERSON_INFO, A.ACTIVITY, DECODE( A.AFFIRM_TYPE, '3', DECODE(A.AFFIRM_FLAG, '0', 'Not Announced', 'Announced'), '4', DECODE(A.AFFIRM_FLAG, '2', 'Cancelled', 'Submitted'), DECODE(A.AFFIRM_FLAG, '0', 'Not Approved', '1', 'Approved', 'Rejected') ) AS AFFIRM_FLAG_NAME, HR.LOCAL_NAME || '/' || GET_CODE_NAME(HR.POST_GRADE_NO, #{lang, jdbcType=VARCHAR}) AS AFFIRM_NAME, GET_DEPT_NAME(HR.DEPTNO, #{lang, jdbcType=VARCHAR}) AS DEPTNAME, A.APPLY_AFFIRM_FLAG AS APPLY_AFFIRM_FLAG_NO, GET_CODE_NAME(A.APPLY_AFFIRM_FLAG, #{lang, jdbcType=VARCHAR}) AS APPLY_AFFIRM_FLAG, TO_CHAR(A.AFFIRM_DATE, 'DD/MM/YYYY HH24:MI:SS') AS UPDATE_DATE, A.AFFIRM_CONTENT FROM SY_AFFIRM_EMAIL A INNER JOIN HR_EMPLOYEE HR ON A.AFFIRM_PERSON_ID = HR.PERSON_ID WHERE TO_CHAR(A.APPLY_NO) = #{applyNo, jdbcType=VARCHAR}
AND A.APPLY_TYPE = #{applyType, jdbcType=VARCHAR}
AND A.APPLY_AFFIRM_FLAG <> '14014310' UNION ALL SELECT '' AS SEQ, '' AS AFFIRM_TYPE, '' AS AFFIRM_TYPE_NAME, TO_CHAR(B.APPLY_NO) AS APPLY_NO, '' AS APPLY_TYPE, '' AS APPLY_FLAG, '' AS APPLY_PERSON_ID, '' AS AFFIRM_PERSON_ID, '' AS TITLE, '100' AS AFFIRM_LEVEL, TO_CHAR(B.CONFIRM_FLAG) AS AFFIRM_FLAG, '' AS AFFIRM_URL, '' AS APPLY_TYPE_CODE, '' AS APPLY_PERSON_INFO, '' AS ACTIVITY, '' AS AFFIRM_FLAG_NAME, GET_LOCAL_NAME_BY_PERSONID(B.CONFIRM_BY, #{lang, jdbcType=VARCHAR}) AS AFFIRM_NAME, 'HR' AS DEPTNAME, '' AS APPLY_AFFIRM_FLAG_NO, '' AS APPLY_AFFIRM_FLAG, TO_CHAR(B.CONFIRM_DATE, 'DD/MM/YYYY HH24:MI:SS') AS UPDATE_DATE, B.HR_COMMENT AS AFFIRM_CONTENT FROM ESS_CARD_APPLY_TB B WHERE TO_CHAR(B.APPLY_NO) = #{applyNo, jdbcType=VARCHAR} ) T ORDER BY TO_NUMBER(T.AFFIRM_LEVEL)
